package policy

import (
	"bytes"
	"context"
	"encoding/json"
	"strings"
	"sync"
	"testing"

	"github.com/sirupsen/logrus"
	"github.com/stretchr/testify/require"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/logging"
)

func TestNewPolicyAuditLogger(t *testing.T) {
	logger := NewPolicyAuditLogger()
	require.NotNil(t, logger)
	require.NotNil(t, logger.logger)
	require.Equal(t, logrus.InfoLevel, logger.logLevel)
}

func TestNewPolicyAuditLoggerWithLevel(t *testing.T) {
	logger := NewPolicyAuditLoggerWithLevel(logrus.DebugLevel)
	require.NotNil(t, logger)
	require.Equal(t, logrus.DebugLevel, logger.logLevel)
}

func TestNewPolicyAuditLoggerWithOutput(t *testing.T) {
	var buf bytes.Buffer
	logger := NewPolicyAuditLoggerWithOutput(&buf, logrus.InfoLevel)
	require.NotNil(t, logger)
	require.Equal(t, logrus.InfoLevel, logger.logLevel)
}

func TestLogDecision(t *testing.T) {
	var buf bytes.Buffer
	logger := NewPolicyAuditLoggerWithOutput(&buf, logrus.InfoLevel)

	testID := identity.NumericIdentity(1001)
	logger.LogDecision(testID, "allow-rule-1", "ALLOW", "matched ingress rule")

	output := buf.String()
	require.NotEmpty(t, output)
	require.Contains(t, output, "allow-rule-1")
	require.Contains(t, output, "ALLOW")
	require.Contains(t, output, "matched ingress rule")
}

func TestLogDecisionJSON(t *testing.T) {
	var buf bytes.Buffer
	logger := NewPolicyAuditLoggerWithOutput(&buf, logrus.InfoLevel)
	logger.SetJSONFormat()

	testID := identity.NumericIdentity(2001)
	logger.LogDecision(testID, "test-policy", "DENY", "no matching rules")

	output := buf.String()
	require.NotEmpty(t, output)

	// Parse the JSON output to verify structure
	var logEntry map[string]interface{}
	err := json.Unmarshal([]byte(output), &logEntry)
	require.NoError(t, err)
	require.Equal(t, "test-policy", logEntry["policy"])
	require.Equal(t, "DENY", logEntry["verdict"])
	require.Equal(t, "no matching rules", logEntry["reason"])
}

func TestLogEvaluation(t *testing.T) {
	var buf bytes.Buffer
	logger := NewPolicyAuditLoggerWithOutput(&buf, logrus.DebugLevel)

	ctx := context.Background()
	policyKey := "test-policy-key"
	logger.LogEvaluation(ctx, policyKey, nil, "test result")

	output := buf.String()
	require.NotEmpty(t, output)
	require.Contains(t, output, policyKey)
}

func TestLogEvaluationWithContext(t *testing.T) {
	var buf bytes.Buffer
	logger := NewPolicyAuditLoggerWithOutput(&buf, logrus.DebugLevel)
	logger.SetJSONFormat()

	ctx := context.WithValue(context.Background(), "traceID", "trace-123")
	policyKey := "test-key"
	logger.LogEvaluation(ctx, policyKey, nil, "evaluation result")

	output := buf.String()
	require.NotEmpty(t, output)
	require.Contains(t, output, "trace-123")
}

func TestLogEvaluationWithIdentities(t *testing.T) {
	var buf bytes.Buffer
	logger := NewPolicyAuditLoggerWithOutput(&buf, logrus.DebugLevel)

	policyKey := "policy-1"
	fromID := identity.NumericIdentity(100)
	toID := identity.NumericIdentity(200)

	logger.LogEvaluationWithIdentities(policyKey, fromID, toID, true)

	output := buf.String()
	require.NotEmpty(t, output)
	require.Contains(t, output, "allowed")
}

func TestLogEvaluationWithIdentitiesDenied(t *testing.T) {
	var buf bytes.Buffer
	logger := NewPolicyAuditLoggerWithOutput(&buf, logrus.DebugLevel)

	policyKey := "policy-deny"
	fromID := identity.NumericIdentity(300)
	toID := identity.NumericIdentity(400)

	logger.LogEvaluationWithIdentities(policyKey, fromID, toID, false)

	output := buf.String()
	require.NotEmpty(t, output)
	require.Contains(t, output, "denied")
}

func TestSetLogLevel(t *testing.T) {
	var buf bytes.Buffer
	logger := NewPolicyAuditLoggerWithOutput(&buf, logrus.InfoLevel)

	// At Info level, Debug logs should not appear
	testID := identity.NumericIdentity(500)
	logger.logger.WithField("test", "debug").Debug("This should not appear")
	require.Empty(t, buf.String())

	// Change to Debug level
	logger.SetLogLevel(logrus.DebugLevel)

	// Now Debug logs should appear
	logger.logger.WithField("test", "debug").Debug("This should appear")
	output := buf.String()
	require.NotEmpty(t, output)
}

func TestSetJSONFormat(t *testing.T) {
	var buf bytes.Buffer
	logger := NewPolicyAuditLoggerWithOutput(&buf, logrus.InfoLevel)
	logger.SetJSONFormat()

	testID := identity.NumericIdentity(600)
	logger.LogDecision(testID, "json-test", "ALLOW", "test reason")

	output := buf.String()
	var logEntry map[string]interface{}
	err := json.Unmarshal([]byte(output), &logEntry)
	require.NoError(t, err)
	require.NotNil(t, logEntry)
}

func TestSetTextFormat(t *testing.T) {
	var buf bytes.Buffer
	logger := NewPolicyAuditLoggerWithOutput(&buf, logrus.InfoLevel)
	logger.SetJSONFormat()
	logger.SetTextFormat()

	testID := identity.NumericIdentity(700)
	logger.LogDecision(testID, "text-test", "ALLOW", "text format test")

	output := buf.String()
	require.NotEmpty(t, output)
	// Text format should not be JSON
	var logEntry map[string]interface{}
	err := json.Unmarshal([]byte(output), &logEntry)
	// Should fail to parse as JSON since it's text format
	if err == nil {
		// Some text formatters might still produce JSON-like output
		// Just verify the content is there
		require.Contains(t, output, "text-test")
	}
}

func TestThreadSafety(t *testing.T) {
	var buf bytes.Buffer
	logger := NewPolicyAuditLoggerWithOutput(&buf, logrus.InfoLevel)

	// Run multiple goroutines logging concurrently
	var wg sync.WaitGroup
	numGoroutines := 10
	logsPerGoroutine := 50

	for i := 0; i < numGoroutines; i++ {
		wg.Add(1)
		go func(index int) {
			defer wg.Done()
			for j := 0; j < logsPerGoroutine; j++ {
				id := identity.NumericIdentity(index*1000 + j)
				logger.LogDecision(id, "policy", "ALLOW", "test")
				logger.LogEvaluationWithIdentities("policy", id, id+1, true)
			}
		}(i)
	}

	wg.Wait()

	// Verify output has entries from all goroutines
	output := buf.String()
	require.NotEmpty(t, output)
	lines := strings.Split(strings.TrimSpace(output), "\n")
	expectedLines := numGoroutines * logsPerGoroutine * 2 // 2 logs per iteration
	// Allow some tolerance since lines might be merged
	require.GreaterOrEqual(t, len(lines), expectedLines/2)
}

func TestConcurrentLogLevelChanges(t *testing.T) {
	var buf bytes.Buffer
	logger := NewPolicyAuditLoggerWithOutput(&buf, logrus.InfoLevel)

	var wg sync.WaitGroup
	done := make(chan bool)

	// One goroutine logging
	wg.Add(1)
	go func() {
		defer wg.Done()
		for i := 0; i < 100; i++ {
			select {
			case <-done:
				return
			default:
				logger.LogDecision(identity.NumericIdentity(i), "policy", "ALLOW", "test")
			}
		}
	}()

	// Another goroutine changing log level
	wg.Add(1)
	go func() {
		defer wg.Done()
		for i := 0; i < 10; i++ {
			if i%2 == 0 {
				logger.SetLogLevel(logrus.DebugLevel)
			} else {
				logger.SetLogLevel(logrus.InfoLevel)
			}
		}
	}()

	wg.Wait()
	close(done)

	output := buf.String()
	require.NotEmpty(t, output)
}

func TestLogDecisionWithDifferentIdentities(t *testing.T) {
	var buf bytes.Buffer
	logger := NewPolicyAuditLoggerWithOutput(&buf, logrus.InfoLevel)

	identities := []identity.NumericIdentity{1, 100, 1000, 65535}
	for _, id := range identities {
		logger.LogDecision(id, "policy", "ALLOW", "reason")
	}

	output := buf.String()
	for _, id := range identities {
		require.Contains(t, output, id.String())
	}
}

func TestLogDecisionMetadata(t *testing.T) {
	var buf bytes.Buffer
	logger := NewPolicyAuditLoggerWithOutput(&buf, logrus.InfoLevel)
	logger.SetJSONFormat()

	testID := identity.NumericIdentity(9999)
	policy := "complex-policy"
	verdict := "ALLOW"
	reason := "matched ingress from trusted namespace"

	logger.LogDecision(testID, policy, verdict, reason)

	output := buf.String()
	var logEntry map[string]interface{}
	err := json.Unmarshal([]byte(output), &logEntry)
	require.NoError(t, err)

	require.Equal(t, policy, logEntry["policy"])
	require.Equal(t, verdict, logEntry["verdict"])
	require.Equal(t, reason, logEntry["reason"])
	require.NotNil(t, logEntry[logfields.Identity])
}

