// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

package policy

import (
	"context"
	"io"

	"github.com/sirupsen/logrus"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/lock"
	"github.com/cilium/cilium/pkg/logging"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

// PolicyAuditLogger provides structured logging of policy evaluation decisions
// for audit and debugging purposes. It is thread-safe and supports JSON-structured
// audit log output.
type PolicyAuditLogger struct {
	// mutex protects concurrent access to the logger fields
	mutex lock.Mutex

	// logger is the underlying logrus logger instance
	logger *logrus.Logger

	// logLevel is the minimum log level for audit entries
	logLevel logrus.Level

	// output is optional custom output for audit logs (defaults to DefaultLogger output)
	output io.Writer
}

// NewPolicyAuditLogger creates a new PolicyAuditLogger with default settings.
// The logger uses the DefaultLogger from the logging package and logs at Info level.
func NewPolicyAuditLogger() *PolicyAuditLogger {
	return &PolicyAuditLogger{
		logger:   logging.DefaultLogger,
		logLevel: logrus.InfoLevel,
	}
}

// NewPolicyAuditLoggerWithLevel creates a new PolicyAuditLogger with a specified log level.
func NewPolicyAuditLoggerWithLevel(level logrus.Level) *PolicyAuditLogger {
	return &PolicyAuditLogger{
		logger:   logging.DefaultLogger,
		logLevel: level,
	}
}

// NewPolicyAuditLoggerWithOutput creates a new PolicyAuditLogger with custom output.
// If output is provided, a new logger instance is created that writes to that output.
func NewPolicyAuditLoggerWithOutput(output io.Writer, level logrus.Level) *PolicyAuditLogger {
	logger := logrus.New()
	logger.SetOutput(output)
	logger.SetLevel(level)
	logger.SetFormatter(logging.GetFormatter(logging.DefaultLogFormatJSON))

	return &PolicyAuditLogger{
		logger:   logger,
		logLevel: level,
		output:   output,
	}
}

// SetLogLevel updates the log level for the audit logger.
func (pal *PolicyAuditLogger) SetLogLevel(level logrus.Level) {
	pal.mutex.Lock()
	defer pal.mutex.Unlock()
	pal.logLevel = level
	pal.logger.SetLevel(level)
}

// SetJSONFormat configures the logger to output in JSON format.
func (pal *PolicyAuditLogger) SetJSONFormat() {
	pal.mutex.Lock()
	defer pal.mutex.Unlock()
	pal.logger.SetFormatter(logging.GetFormatter(logging.LogFormatJSON))
}

// SetTextFormat configures the logger to output in text format.
func (pal *PolicyAuditLogger) SetTextFormat() {
	pal.mutex.Lock()
	defer pal.mutex.Unlock()
	pal.logger.SetFormatter(logging.GetFormatter(logging.LogFormatText))
}

// LogDecision logs a policy decision with structured fields.
// It records which identity made a decision about a policy and the outcome.
func (pal *PolicyAuditLogger) LogDecision(identity identity.NumericIdentity, policy string, verdict string, reason string) {
	pal.mutex.Lock()
	defer pal.mutex.Unlock()

	fields := logrus.Fields{
		logfields.Identity: identity,
		"policy":           policy,
		"verdict":          verdict,
		"reason":           reason,
	}

	pal.logger.WithFields(fields).Info("Policy decision")
}

// LogEvaluation logs the evaluation of a policy against a selector cache result.
// This method is used to track how policy rules are matched against identities.
func (pal *PolicyAuditLogger) LogEvaluation(ctx context.Context, policyKey string, selectorCache *SelectorCache, result interface{}) {
	pal.mutex.Lock()
	defer pal.mutex.Unlock()

	fields := logrus.Fields{
		logfields.PolicyKey: policyKey,
	}

	// Add context-based tracing information if available
	if traceID := ctx.Value("traceID"); traceID != nil {
		fields["traceID"] = traceID
	}

	// Add result information if provided
	if result != nil {
		fields["result"] = result
	}

	pal.logger.WithFields(fields).Debug("Policy evaluation")
}

// LogEvaluationWithIdentities logs the evaluation of a policy with specific identities.
// This is useful for tracking selector cache interactions during policy evaluation.
func (pal *PolicyAuditLogger) LogEvaluationWithIdentities(policyKey string, fromIdentity, toIdentity identity.NumericIdentity, allowed bool) {
	pal.mutex.Lock()
	defer pal.mutex.Unlock()

	fields := logrus.Fields{
		logfields.PolicyKey:   policyKey,
		logfields.Identity:    fromIdentity,
		"toIdentity":          toIdentity,
		"allowed":             allowed,
	}

	action := "denied"
	if allowed {
		action = "allowed"
	}

	pal.logger.WithFields(fields).Debug("Policy evaluation with identities: " + action)
}

